            XMLReader xmlReader = SAX_PARSER_FACTORY.newSAXParser().getXMLReader();
            InputSource inputSource = new InputSource(new StringReader(xmlData));
            SAXSource saxSource = new SAXSource(xmlReader, inputSource);

